ge", "evidence": ["用户查询中'\''张三'\''为完整中文姓名，按 capability_manifest notes 必须保留全名", "searchClientName 支持 MATCH 操作符，符合 capability_manifest", "查询中无其他筛选意图，不应附加额外条件"], "expected_source": "not_available", "source": "从用户查询语义和 capability_manifest 实时推导"}, "scenario": "单条件姓名精确匹配", "summary": {"assessment_count": 4, "blocking_count": 3, "fulfillment_status": "fulfilled", "is_formal_attribution": true, "reason": "fulfilled · 3 blocking expectations all met · 用户意图是按客户本人姓名'\''张三'\''查找客户记录。parser 输出 searchClientName + MATCH + '\''张三'\''，完全符合 capability_manifest 中该字段的定义（客户本人姓名）、操作符允许范围（MATCH 是合法操作符）和值规则（完整姓名保留）。'\''详细资料'\''属于展示层面需求，不产生额外搜索条件。所有业务期望均 fulfilled，无 missing、wrong 或 extra 问题。", "reason_source": "aggregated_fulfillment"}, "trace_id": "8ab8fab7-eb8a-4ade-8e11-c6f219f82ae6", "transition_decisions": [{"condition": "always", "from_state": "prepare_trace", "reason": "always", "retry_count": 0, "stop_reason": "", "to_state": "mock_or_input"}, {"condition": "always", "from_state": "mock_or_input", "reason": "always", "retry_count": 0, "stop_reason": "", "to_state": "execute_or_capture"}, {"condition": "always", "from_state": "execute_or_capture", "gate_ids": ["trace_available"], "reason": "always", "retry_count": 0, "stop_reason": "", "to_state": "collect_evidence"}, {"condition": "always", "from_state": "collect_evidence", "reason": "always", "retry_count": 0, "stop_reason": "", "to_state": "build_business_expectations"}, {"condition": "always", "from_state": "build_business_expectations", "gate_ids": ["consumer_contract_present", "business_expectation_coverage"], "reason": "always", "retry_count": 0, "stop_reason": "", "to_state": "evaluate_fulfillment"}, {"condition": "always", "from_state": "evaluate_fulfillment", "gate_ids": ["fulfillment_assessment_coverage", "boundary_decision_present", "derived_verdict_consistency"], "reason": "always", "retry_count": 0, "stop_reason": "", "to_state": "fulfillment_critic"}, {"condition": "fulfillment_requires_attribute", "from_state": "fulfi